const STYLES = "/* ===== tokens.css ===== */\n/* skill-lab — color tokens (THE single source of truth)\n * Built & measured by atelier:color (see color-build.mjs + COLOR-REPORT.md).\n * Three layers: raw oklch ramp → semantic alias → component reads ONLY the alias.\n * Theme switch = remap the alias layer (NOT filter:invert). Hex in comments = sRGB fallback.\n *\n * CONSISTENCY (local ≡ claude.ai): this block is the canonical source; it is embedded\n * VERBATIM into both web/index.html and the JSX artifact's <style>. Never hand-type a\n * color in a component — reference var(--…) so the two targets cannot drift.\n */\n\n:root {\n  color-scheme: light;\n\n  /* ---- raw neutral ramp — WARM paper&ink (H 85, low chroma, no pure gray) ---- */\n  --paper-50:  oklch(0.985 0.004 85);  /* #fbfaf7 page (paper)        */\n  --paper-100: oklch(0.967 0.006 85);  /* #f6f4f0 raised surface      */\n  --paper-150: oklch(0.945 0.008 85);  /* #efece7 recessed / track    */\n  --n-200:     oklch(0.905 0.010 85);  /* #e3dfd8 faint rule          */\n  --n-300:     oklch(0.850 0.012 85);  /* #d1cdc5 hairline / divider  */\n  --n-400:     oklch(0.720 0.014 85);  /* #a9a49b disabled            */\n  --n-500:     oklch(0.620 0.015 85);  /* #8a867c placeholder / fn-border */\n  --n-600:     oklch(0.520 0.016 85);  /* #6d685f tertiary text       */\n  --n-700:     oklch(0.430 0.016 85);  /* #544f46 secondary text      */\n  --n-800:     oklch(0.320 0.014 85);  /* #36322b strong text         */\n  --ink:       oklch(0.235 0.012 85);  /* #211e18 primary text (ink)  */\n  --ink-950:   oklch(0.180 0.010 85);  /* #14110d headline / max ink  */\n\n  /* ---- raw accent ramp — deep evergreen (H 158); accent-600 is the canon anchor ---- */\n  --accent-700: oklch(0.420 0.078 158); /* #205a3c hover               */\n  --accent-600: oklch(0.470 0.075 158); /* #32684a link/brand/positive */\n  --accent-500: oklch(0.560 0.090 158); /* #418460                     */\n  --accent-300: oklch(0.760 0.075 158); /* #88c09f dark-mode accent    */\n  --accent-200: oklch(0.860 0.045 158); /* #b9dac6                     */\n\n  /* ---- raw semantics ---- */\n  --neg-raw:    oklch(0.500 0.060 55);  /* #7e5a42 sober ochre-brown (NOT alarmist red) */\n  --err-raw:    oklch(0.500 0.130 28);  /* #a04037 genuine system error */\n  --err-bg-raw: oklch(0.960 0.020 30);  /* #ffedea                     */\n\n  /* ===== semantic alias layer (components read ONLY these) — LIGHT ===== */\n  --bg:            var(--paper-50);\n  --surface:       var(--paper-100);\n  --surface-2:     var(--paper-150);   /* recessed input fill / bar track */\n  --elevated:      var(--paper-50);    /* result panel sits on paper, lifted by shadow not fill */\n  --text:          var(--ink);\n  --text-strong:   var(--ink-950);\n  --text-2:        var(--n-700);       /* secondary — caveats live here, NEVER dialed paler */\n  --text-3:        var(--n-600);       /* tertiary / caption */\n  --placeholder:   var(--n-500);\n  --border-subtle: var(--n-300);       /* decorative rule / section hairline (1.4.11-exempt) */\n  --border-strong: var(--n-500);       /* functional input/interactive border (≥3:1) */\n  --accent:        var(--accent-600);\n  --accent-hover:  var(--accent-700);\n  --on-accent:     var(--paper-50);\n  --link:          var(--accent-600);\n  --focus:         var(--accent-600);\n  --delta-pos:     var(--accent-600);  /* positive / zero delta */\n  --delta-neg:     var(--neg-raw);     /* negative delta (sober) */\n  --error:         var(--err-raw);\n  --error-bg:      var(--err-bg-raw);\n\n  /* ---- data-viz (categorical, n=2; gray the control, spend color on the signal) ---- */\n  --viz-track:     var(--paper-150);\n  --viz-base:      var(--n-600);       /* \"no skill\" arm — grayed, de-emphasized */\n  --viz-treat:     var(--accent-600);  /* \"skill as workflow\" arm — the signal   */\n}\n\n/* ===== DARK — re-tuned ramp (NOT invert): deep warm base, elevation by lighter surface,\n   off-white text, accent L↑ C↓. Zero-JS baseline via @media; [data-theme] overrides it. ===== */\n@media (prefers-color-scheme: dark) {\n  :root:not([data-theme=\"light\"]) {\n    color-scheme: dark;\n    --bg:            oklch(0.150 0.008 85);  /* deep warm gray (halation-safe, not #000) */\n    --surface:       oklch(0.190 0.009 85);  /* raised by LIGHTER surface */\n    --surface-2:     oklch(0.235 0.010 85);\n    --elevated:      oklch(0.235 0.010 85);  /* result panel = highest surface */\n    --text:          oklch(0.910 0.006 85);  /* off-white, not #fff */\n    --text-strong:   oklch(0.950 0.005 85);\n    --text-2:        oklch(0.865 0.008 85);  /* secondary (APCA-tuned) */\n    --text-3:        oklch(0.790 0.010 85);  /* tertiary */\n    --placeholder:   oklch(0.560 0.011 85);\n    --border-subtle: oklch(0.340 0.010 85);\n    --border-strong: oklch(0.700 0.013 85);\n    --accent:        oklch(0.760 0.072 158); /* L↑ C↓ vs light */\n    --accent-hover:  oklch(0.700 0.075 158);\n    --on-accent:     oklch(0.180 0.010 85);\n    --link:          oklch(0.760 0.072 158);\n    --focus:         oklch(0.760 0.072 158);\n    --delta-pos:     oklch(0.760 0.072 158);\n    --delta-neg:     oklch(0.770 0.065 60);\n    --error:         oklch(0.780 0.110 28);\n    --error-bg:      oklch(0.260 0.040 28);\n    --viz-track:     oklch(0.190 0.009 85);\n    --viz-base:      oklch(0.620 0.012 85);  /* grayed control */\n    --viz-treat:     oklch(0.760 0.072 158); /* signal */\n  }\n}\n\n/* explicit overrides for the three-state toggle (light / dark / system) */\n[data-theme=\"dark\"] {\n  color-scheme: dark;\n  --bg: oklch(0.150 0.008 85); --surface: oklch(0.190 0.009 85); --surface-2: oklch(0.235 0.010 85);\n  --elevated: oklch(0.235 0.010 85); --text: oklch(0.910 0.006 85); --text-strong: oklch(0.950 0.005 85);\n  --text-2: oklch(0.865 0.008 85); --text-3: oklch(0.790 0.010 85); --placeholder: oklch(0.560 0.011 85);\n  --border-subtle: oklch(0.340 0.010 85); --border-strong: oklch(0.700 0.013 85);\n  --accent: oklch(0.760 0.072 158); --accent-hover: oklch(0.700 0.075 158); --on-accent: oklch(0.180 0.010 85);\n  --link: oklch(0.760 0.072 158); --focus: oklch(0.760 0.072 158);\n  --delta-pos: oklch(0.760 0.072 158); --delta-neg: oklch(0.770 0.065 60);\n  --error: oklch(0.780 0.110 28); --error-bg: oklch(0.260 0.040 28);\n  --viz-track: oklch(0.190 0.009 85); --viz-base: oklch(0.620 0.012 85); --viz-treat: oklch(0.760 0.072 158);\n}\n/* [data-theme=\"light\"] inherits :root (the light default) — no override needed. */\n\n\n/* ===== type.css ===== */\n/* skill-lab — type system (single source). Built by atelier:type.\n * Pairs with tokens.css (color). Components reference these tokens / classes — never a magic px.\n *\n * FONT STRATEGY = system stacks (decided: identity over flourish).\n * No webfont, no @font-face, no CDN → local ≡ claude.ai render identically on a given device,\n * zero CLS, zero FOUT by construction. (Metrics-matched fallback is N/A: there is no webfont to swap.)\n * Cost accepted: no bespoke Newsreader serif; ui-serif (Apple = New York) carries the quiet\n * authoritative headline — Apple/OpenAI-native, fitting the \"honest instrument\" POV.\n */\n\n:root {\n  /* ---- families ---- */\n  --font-serif: ui-serif, \"New York\", Georgia, \"Times New Roman\", serif;          /* headline (quiet authority) */\n  --font-sans:  ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif; /* UI / body */\n  --font-mono:  ui-monospace, \"SF Mono\", \"Menlo\", \"Cascadia Code\", Consolas, monospace; /* data / delta / IDs */\n\n  /* ---- type scale — fluid clamp(), rem intercept (WCAG 1.4.4 safe). Editorial regime: ratio 1.333.\n         Range: 360px → 1040px viewport. The delta numeral is the largest (signature > headline). ---- */\n  --t-delta:   clamp(2.75rem, 2.088rem + 2.94vw, 4rem);     /* 44 → 64  signature metric (mono, tabular) */\n  --t-h1:      clamp(1.875rem, 1.544rem + 1.47vw, 2.5rem);  /* 30 → 40  serif headline (quiet, < delta)  */\n  --t-h2:      clamp(1.5rem, 1.30rem + 0.88vw, 1.875rem);   /* 24 → 30 */\n  --t-h3:      clamp(1.25rem, 1.117rem + 0.59vw, 1.5rem);   /* 20 → 24 */\n  --t-lead:    clamp(1.125rem, 1.026rem + 0.44vw, 1.3125rem); /* 18 → 21 lead/method blurb */\n  --t-body:    1rem;        /* 16  body / method prose */\n  /* ---- compact UI cluster — near-linear ~1.125 (deliberate tool-UI exception) ---- */\n  --t-ui:      0.875rem;    /* 14  controls / table body */\n  --t-small:   0.8125rem;   /* 13  secondary control text */\n  --t-caption: 0.75rem;     /* 12  caption / caveat / log */\n  --t-eyebrow: 0.6875rem;   /* 11  uppercase section label */\n\n  /* ---- line-height (inverse with size) ---- */\n  --lh-display: 1.05;   /* delta / display */\n  --lh-heading: 1.18;   /* h1–h3 (≤1.25) */\n  --lh-body:    1.6;    /* body (≥1.5) */\n  --lh-small:   1.65;   /* small / caption (≥1.6) */\n\n  /* ---- tracking (three-level) ---- */\n  --ls-display: -0.022em;  /* display / headline (≤ −0.02) */\n  --ls-body:    0;\n  --ls-eyebrow: 0.085em;   /* uppercase eyebrow / all-caps (+0.05…0.10) */\n\n  /* ---- weights (hierarchy = size × weight, both tokenized) ---- */\n  --fw-reg: 400; --fw-med: 500; --fw-semi: 600; --fw-bold: 700;\n\n  /* ---- measure ---- */\n  --measure: 68ch;   /* running prose cap (~65–70ch) */\n\n  /* ---- spacing scale (STAGE 1) — base 4px, half-geometric; rem rhythm (md = 1rem = one body line-ish) ---- */\n  --space-base: 4px;\n  --space-2xs: 0.25rem;  /*  4 */\n  --space-xs:  0.5rem;   /*  8 */\n  --space-sm:  0.75rem;  /* 12 */\n  --space-md:  1rem;     /* 16 */\n  --space-lg:  1.5rem;   /* 24 */\n  --space-xl:  2rem;     /* 32 */\n  --space-2xl: 3rem;     /* 48 */\n  --space-3xl: 4rem;     /* 64 */\n  --space-4xl: 6rem;     /* 96 */\n  /* Group-proximity law (gate): section gap (≥2xl) ≥ 2× intra-group gap (md/lg). The editorial\n     \"float on paper\" depends on it — sections separated by ≥ 2× the within-card spacing. */\n}\n\n/* ================= base typographic rules ================= */\nbody, .ui {\n  font-family: var(--font-sans);\n  font-size: var(--t-body);\n  line-height: var(--lh-body);\n  letter-spacing: var(--ls-body);\n  font-variant-numeric: oldstyle-nums;     /* prose numbers sit in text; data uses .mono/.tnum */\n  -webkit-font-smoothing: antialiased;\n  text-rendering: optimizeLegibility;\n}\n\n/* the quiet authoritative serif headline (NOT the signature — kept < delta) */\n.headline {\n  font-family: var(--font-serif);\n  font-size: var(--t-h1);\n  line-height: var(--lh-heading);\n  letter-spacing: var(--ls-display);\n  font-weight: var(--fw-semi);\n  text-wrap: balance;                       /* no orphaned last line on multi-line headings */\n}\n.h2 { font-family: var(--font-serif); font-size: var(--t-h2); line-height: var(--lh-heading); letter-spacing: var(--ls-display); font-weight: var(--fw-semi); text-wrap: balance; }\n.h3 { font-size: var(--t-h3); line-height: var(--lh-heading); font-weight: var(--fw-semi); text-wrap: balance; }\n\n/* method blurb / lead reading */\n.lead  { font-size: var(--t-lead); line-height: var(--lh-body); max-inline-size: var(--measure); text-wrap: pretty; }\n.prose { font-size: var(--t-body); line-height: var(--lh-body); max-inline-size: var(--measure); text-wrap: pretty; }\n\n/* uppercase section eyebrow */\n.eyebrow {\n  font-size: var(--t-eyebrow);\n  letter-spacing: var(--ls-eyebrow);\n  text-transform: uppercase;\n  font-weight: var(--fw-semi);\n  line-height: var(--lh-small);\n  font-feature-settings: \"case\" 1, \"cpsp\" 1;  /* all-caps spacing refinement */\n}\n\n/* caption / caveat / log — secondary/tertiary text (still legible: color sets the floor, not the size) */\n.caption { font-size: var(--t-caption); line-height: var(--lh-small); }\n\n/* data / mono — the signature delta + all numeric columns */\n.mono { font-family: var(--font-mono); font-variant-numeric: tabular-nums lining-nums slashed-zero; }\n.tnum { font-variant-numeric: tabular-nums lining-nums; }   /* any number in a column / updating in place */\n.delta {\n  font-family: var(--font-mono);\n  font-size: var(--t-delta);\n  line-height: var(--lh-display);\n  letter-spacing: var(--ls-display);\n  font-weight: var(--fw-bold);\n  font-variant-numeric: tabular-nums lining-nums slashed-zero;\n}\n\n/* compact UI text (tool cluster) */\n.t-ui    { font-size: var(--t-ui); }\n.t-small { font-size: var(--t-small); }\n\n/* ================= i18n posture (STAGE 2) ================= */\n/* Product decision: the bench UI is English-only (a dev tool for an English-context suite) — full\n   ICU/locale-routing is out of scope by RESTRAINT (over-building for zero real locales). But the\n   cheap structural correctness that prevents real bugs is non-negotiable and applied here: */\n\n/* 1) Logical properties everywhere (RTL-safe insurance at no cost): components use padding-inline,\n      margin-block, inset-inline, gap, max-inline-size, text-align: start — NOT left/right.\n      (Enforced by convention + the .lead/.prose rules above using max-inline-size, not max-width.) */\n\n/* 2) Arbitrary MODEL/USER-generated text — the review bodies and the run log — can contain ANY\n      script (CJK code/comments, RTL, mixed). Isolate direction + break long code tokens safely. */\n.user-text {\n  unicode-bidi: isolate;          /* (use dir=\"auto\" on the element too) — no direction contamination */\n  overflow-wrap: anywhere;        /* long unbroken code tokens / URLs can't overflow the panel */\n  line-break: strict;             /* respect CJK kinsoku (禁則) if the review contains CJK */\n  white-space: pre-wrap;          /* preserve the review's own line breaks (it's quoted code/prose) */\n}\n\n/* 3) tabular-nums on all data (above) so digits don't jitter as values update in place.\n   4) No string-concatenated UI messages with pluralization risk; the few dynamic strings are\n      simple counts shown beside a fixed label, not grammatical sentences that inflect. */\n\n\n/* ===== layout.css ===== */\n/* skill-lab — composition / layout (single source). Built by atelier:layout.\n * Consumes tokens.css (color) + type.css (scale, spacing). Logical properties throughout (RTL-safe).\n * Armature: an editorial single column on paper; sections FLOAT (no card-soup), separated by\n * whitespace + a hairline rule + an uppercase label-gutter. The result panel is the ONE elevated\n * surface (form lens supplies the shadow). Focal element = the delta numeral (resulted) / the\n * headline + Run CTA (empty).\n */\n\n/* ---------- shell & masthead ---------- */\n.shell {\n  max-inline-size: 54rem;                 /* ~864px; content column lands ~68ch */\n  margin-inline: auto;\n  padding-inline: clamp(var(--space-md), 4vw, var(--space-2xl));\n  padding-block: var(--space-xl) var(--space-3xl);\n}\n.masthead {\n  display: flex; align-items: center; justify-content: space-between; gap: var(--space-md);\n  padding-block-end: var(--space-md);\n  border-block-end: 1px solid var(--border-subtle);\n  margin-block-end: var(--space-2xl);\n}\n.wordmark { display: inline-flex; align-items: center; gap: var(--space-xs); font-weight: var(--fw-semi); }\n.brand-dot { inline-size: 0.5rem; block-size: 0.5rem; border-radius: 9999px; background: var(--accent); }\n.badge {\n  font-size: var(--t-eyebrow); letter-spacing: var(--ls-eyebrow); text-transform: uppercase;\n  color: var(--text-3); display: inline-flex; align-items: center; gap: var(--space-2xs);\n}\n.badge::before { content: \"\"; inline-size: 0.4rem; block-size: 0.4rem; border-radius: 9999px; background: var(--text-3); }\n.badge[data-env=\"local\"]::before    { background: var(--accent); }\n.badge[data-env=\"claudeai\"]::before { background: var(--accent); }\n.badge[data-env=\"detecting\"]::before{ background: var(--border-strong); animation: pulse 1.4s ease-in-out infinite; }\n\n/* ---------- the label-gutter section grid (Stripe/Tailwind-docs idiom) ---------- */\n.section {\n  display: grid;\n  grid-template-columns: [label] 9rem [content] minmax(0, 1fr);\n  gap: var(--space-lg);\n  padding-block-start: var(--space-2xl);\n  margin-block-start: var(--space-2xl);\n  border-block-start: 1px solid var(--border-subtle);\n}\n.section:first-of-type { margin-block-start: 0; padding-block-start: 0; border-block-start: 0; }\n.gutter-label { grid-column: label; align-self: start; } /* an .eyebrow lives here, hangs in the rail */\n.section-body { grid-column: content; min-inline-size: 0; }            /* min-inline-size:0 = grid overflow guard */\n.section-body > * + * { margin-block-start: var(--space-md); }         /* intra-section rhythm */\n\n/* hero/question section: headline + method blurb (the empty-screen focal) */\n.hero .headline { margin-block-end: var(--space-sm); }\n\n/* ---------- forms / tool cluster (compact density) ---------- */\n.field-grid { display: flex; flex-wrap: wrap; gap: var(--space-sm) var(--space-md); align-items: end; }\n.field { display: flex; flex-direction: column; gap: var(--space-2xs); min-inline-size: 0; flex: 1 1 12rem; }\n.field > label, .field-label { font-size: var(--t-small); color: var(--text-2); }\n.field input, .field select, .input, .select {\n  font-family: var(--font-sans); font-size: var(--t-ui); color: var(--text);\n  background: var(--surface-2);                       /* recessed (ground-colored) input */\n  border: 1px solid var(--border-strong);             /* functional border (≥3:1) */\n  border-radius: var(--radius-sm, 6px);\n  padding-block: var(--space-xs); padding-inline: var(--space-sm);\n  min-block-size: 2.75rem;                             /* ≥44px touch target */\n}\n.field input::placeholder { color: var(--placeholder); }\n.field input:focus-visible, .field select:focus-visible, .btn-run:focus-visible, summary:focus-visible {\n  outline: 2px solid var(--focus); outline-offset: 2px;\n}\n.field input:disabled, .field select:disabled { opacity: 0.55; cursor: not-allowed; }\n\n/* delivery arms */\n.arm-row { display: flex; flex-direction: column; gap: var(--space-2xs);\n  padding-block: var(--space-xs); min-block-size: 2.75rem; }\n.arm-row .arm-head { display: flex; align-items: center; gap: var(--space-xs); font-weight: var(--fw-med); }\n.arm-row input[type=\"checkbox\"] { inline-size: 1.1rem; block-size: 1.1rem; accent-color: var(--accent); }\n.arm-row .arm-blurb { font-size: var(--t-small); color: var(--text-2); }\n.tag-pill { font-size: var(--t-eyebrow); letter-spacing: var(--ls-eyebrow); text-transform: uppercase;\n  color: var(--text-3); border: 1px solid var(--border-subtle); border-radius: 9999px;\n  padding-inline: var(--space-xs); padding-block: 1px; }\n\n/* ---------- controls + cost line ---------- */\n.controls { display: flex; flex-wrap: wrap; align-items: center; gap: var(--space-md); }\n.btn-run {\n  font: inherit; font-weight: var(--fw-semi); font-size: var(--t-ui);\n  color: var(--on-accent); background: var(--accent); border: 0;\n  border-radius: var(--radius-sm, 6px);\n  padding-block: var(--space-sm); padding-inline: var(--space-lg);\n  min-block-size: 2.75rem; cursor: pointer;            /* the ONE colored action (primary CTA) */\n}\n.btn-run:hover:not(:disabled) { background: var(--accent-hover); }\n.btn-run:disabled { opacity: 0.45; cursor: not-allowed; }\n.cost-line { font-size: var(--t-caption); color: var(--text-3); }\n\n/* ---------- the result panel — the ONE elevated surface; the delta is the focal element ---------- */\n.result-panel {\n  grid-column: 1 / -1;                                 /* breaks the label-gutter — full content width */\n  background: var(--elevated);\n  border: 1px solid var(--border-subtle);\n  border-radius: var(--radius-lg, 12px);               /* form lens supplies shadow + concentric radii */\n  padding: var(--space-xl);\n  margin-block-start: var(--space-2xl);\n}\n.delta-row { display: flex; align-items: baseline; gap: var(--space-md); flex-wrap: wrap;\n  margin-block: var(--space-sm) var(--space-lg); }\n.delta { color: var(--delta-pos); }                    /* .delta sizing in type.css */\n.delta[data-sign=\"neg\"] { color: var(--delta-neg); }   /* equal dignity — same size/panel, only color+sign differ */\n.delta-caption { font-size: var(--t-small); color: var(--text-2); }\n\n/* per-arm score bars (data-viz: gray base, accent treat; bar fills via scaleX in motion lens) */\n.arm-score { margin-block-start: var(--space-md); }\n.arm-score-head { display: flex; justify-content: space-between; align-items: baseline;\n  font-size: var(--t-small); margin-block-end: var(--space-2xs); }\n.bar-track { block-size: 0.5rem; border-radius: 9999px; background: var(--viz-track); overflow: hidden; }\n.bar-fill  { block-size: 100%; border-radius: 9999px; transform-origin: inline-start; }\n.bar-fill[data-arm=\"base\"]    { background: var(--viz-base); }\n.bar-fill[data-arm=\"harness\"] { background: var(--viz-treat); }\n.per-fixture { margin-block-start: var(--space-lg); font-size: var(--t-small); color: var(--text-2); }\n.per-fixture > * + * { margin-block-start: var(--space-2xs); }\n\n/* ---------- why / per-trial breakdown ---------- */\n.why-group { margin-block-start: var(--space-lg); }\n.why-group-head { font-size: var(--t-small); font-weight: var(--fw-semi); margin-block-end: var(--space-xs); }\ndetails.trial { border-block-start: 1px solid var(--border-subtle); }\ndetails.trial > summary {\n  cursor: pointer; list-style: none; padding-block: var(--space-xs);\n  font-size: var(--t-small); min-block-size: 2.75rem; display: flex; align-items: center; gap: var(--space-xs);\n}\ndetails.trial > summary::-webkit-details-marker { display: none; }\n.review-body {                                          /* arbitrary model text — see type.css .user-text */\n  font-family: var(--font-mono); font-size: var(--t-caption); color: var(--text-2);\n  background: var(--surface); border-radius: var(--radius-sm, 6px);\n  padding: var(--space-sm); margin-block-start: var(--space-xs);\n  max-block-size: 28rem; overflow: auto; scrollbar-gutter: stable;\n}\n\n/* ---------- run log ---------- */\n.log {\n  font-family: var(--font-mono); font-size: var(--t-caption); color: var(--text-3);\n  line-height: var(--lh-small); max-block-size: 24rem; overflow: auto; scrollbar-gutter: stable;\n}\n\n/* ---------- state blocks ---------- */\n.error-block {                                          /* DISTINCT from empty — a designed product moment */\n  grid-column: 1 / -1;\n  background: var(--error-bg); color: var(--error);\n  border: 1px solid var(--error); border-radius: var(--radius-sm, 6px);\n  padding: var(--space-md); font-size: var(--t-ui);\n}\n.error-block .retry-hint { color: var(--text-2); font-size: var(--t-small); }\n.warn-inline {                                          /* harness-unavailable: caution, not alarm */\n  font-size: var(--t-small); color: var(--text-2);\n  border-inline-start: 2px solid var(--border-strong);\n  padding-inline-start: var(--space-sm); margin-block-start: var(--space-sm);\n}\n.skeleton {                                             /* matches result-panel geometry — no layout shift */\n  border-radius: var(--radius-sm, 6px); background: var(--surface-2);\n  animation: pulse 1.4s ease-in-out infinite;\n}\n.skeleton.delta-sk { block-size: 3.5rem; inline-size: 8rem; }\n.skeleton.bar-sk   { block-size: 0.5rem; margin-block-start: var(--space-md); }\n\n/* ---------- footer (read-honestly) ---------- */\n.footer {\n  grid-column: content;\n  margin-block-start: var(--space-3xl); padding-block-start: var(--space-lg);\n  border-block-start: 1px solid var(--border-subtle);\n  font-size: var(--t-caption); color: var(--text-2); max-inline-size: var(--measure);\n}\n\n/* ---------- long-tail / overflow guards ---------- */\n.fixtures-list .repo { font-weight: var(--fw-med); }\n.fixtures-list .file, .truncate-path { overflow-wrap: anywhere; }\n.user-text, .review-body, .log { overflow-wrap: anywhere; }   /* long unbroken code tokens can't blow out */\n\n/* ---------- responsive: stack the label-gutter ≤720px; hold density to 320px ---------- */\n@media (max-width: 720px) {\n  .section { grid-template-columns: 1fr; gap: var(--space-sm); }\n  .gutter-label { grid-column: 1; }\n  .section-body { grid-column: 1; }\n  .footer { grid-column: 1; }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .badge[data-env=\"detecting\"]::before, .skeleton { animation: none; }\n}\n@keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.55; } }\n\n\n/* ===== form.css ===== */\n/* skill-lab — depth & shape (single source). Built by atelier:form.\n * Consumes tokens.css. Restraint is the rule: this is an instrument, not a decorated surface.\n * canon \"kill card-soup\" → only the RESULT panel is elevated (the hero); every other section sits\n * FLAT on the paper (resting), separated by a hairline. Inputs are RECESSED (--surface-2).\n *\n * ONE LIGHT MODEL — light direction = overhead (shadows cast straight down; only size/softness\n * changes per elevation step, never direction). Shadows are hue-tinted (warm, H 85), never black.\n */\n\n:root {\n  /* ---- radius scale (role-mapped) — realises the fallbacks layout.css references ---- */\n  --radius-xs:   4px;     /* chip / tag-pill inner */\n  --radius-sm:   6px;     /* input / button / bar-fill ends / review-body */\n  --radius-md:   8px;\n  --radius-lg:   12px;    /* the result panel (the one elevated surface) */\n  --radius-2xl:  16px;\n  --radius-full: 9999px;  /* pills, dots, bar-track */\n\n  /* ---- elevation z-scale (light): layered cast (≥2) + contact + top-edge highlight + face gradient ---- */\n  --z-resting: none;                                   /* sections: flat on paper, hairline only */\n  --shadow-raised:                                     /* the result panel */\n    0 1px 2px -1px oklch(0.40 0.020 85 / 0.10),         /* contact */\n    0 8px 24px -4px oklch(0.40 0.020 85 / 0.10);        /* ambient */\n  --shadow-overlay:                                    /* native popovers / future menus */\n    0 2px 5px -1px oklch(0.40 0.020 85 / 0.10),\n    0 16px 40px -6px oklch(0.40 0.020 85 / 0.12);\n  --edge-highlight: inset 0 1px 0 oklch(1 0 0 / 0.55); /* top-edge light on the raised face */\n  /* surface gradient on the raised face — job = DEPTH (named, STAGE 2). 1.5% L delta, oklab interp. */\n  --surface-gradient: linear-gradient(in oklab to bottom, oklch(0.990 0.004 85), oklch(0.975 0.006 85));\n}\n\n/* DARK: diffuse shadows nearly vanish — elevation switches mechanism. The lighter --elevated surface\n   (tokens.css) + the top-edge highlight carry the signal; shadow layers thin but persist. */\n@media (prefers-color-scheme: dark) {\n  :root:not([data-theme=\"light\"]) {\n    --shadow-raised:  0 1px 2px oklch(0 0 0 / 0.40), 0 8px 24px -4px oklch(0 0 0 / 0.45);\n    --shadow-overlay: 0 2px 6px oklch(0 0 0 / 0.45), 0 18px 44px -6px oklch(0 0 0 / 0.55);\n    --edge-highlight: inset 0 1px 0 oklch(1 0 0 / 0.08);  /* primary elevation cue on dark */\n    --surface-gradient: linear-gradient(in oklab to bottom, oklch(0.250 0.010 85), oklch(0.228 0.010 85));\n  }\n}\n[data-theme=\"dark\"] {\n  --shadow-raised:  0 1px 2px oklch(0 0 0 / 0.40), 0 8px 24px -4px oklch(0 0 0 / 0.45);\n  --shadow-overlay: 0 2px 6px oklch(0 0 0 / 0.45), 0 18px 44px -6px oklch(0 0 0 / 0.55);\n  --edge-highlight: inset 0 1px 0 oklch(1 0 0 / 0.08);\n  --surface-gradient: linear-gradient(in oklab to bottom, oklch(0.250 0.010 85), oklch(0.228 0.010 85));\n}\n\n/* ---- the one elevated surface ---- */\n.result-panel {\n  box-shadow: var(--edge-highlight), var(--shadow-raised);\n  background-color: var(--elevated);\n  background-image: var(--surface-gradient);          /* face gradient, job = depth */\n  border-color: var(--border-subtle);\n  /* radius-lg already set in layout.css; overflow:hidden so the face gradient + children clip cleanly */\n  overflow: hidden;\n}\n\n/* resting surfaces stay flat — explicit, so no stray shadow creeps in */\n.section, .field, .arm-row, .fixtures-list { box-shadow: var(--z-resting); }\n\n/* CONCENTRIC RADIUS LAW (inner = outer − gap), verified:\n *   result-panel radius-lg(12) has padding --space-xl(32) → inner elements (bars, scores, breakdown)\n *   sit far from the corners (32 ≫ 12), so each keeps its role radius without pinching. The bar-track\n *   is radius-full (a pill — concentric-exempt). review-body radius-sm(6) lives inside <details>, not\n *   flush within a rounded container. No nesting here violates the law.\n * Where a rounded child IS flush to a rounded parent in future, apply: inner = outer − padding (≤0 → 0).\n */\n.bar-track, .bar-fill { border-radius: var(--radius-full); }\n.review-body { border-radius: var(--radius-sm); }\n.tag-pill { border-radius: var(--radius-full); }\n\n/* SHAPE LANGUAGE = plain round, chosen (not defaulted): an instrument reads honest and unfussy;\n * superellipse/bevel would add personality this POV doesn't want. Applied consistently via the scale. */\n\n/* TEXTURE / GRADIENT intent (STAGE 2):\n *   - the ONLY gradient is --surface-gradient (job = DEPTH) on the raised face; interpolated in oklab.\n *   - aurora / mesh / ambient glow: DECLINED on purpose — they are the current \"AI aesthetic\" and the\n *     instrument POV rejects decoration without a job.\n *   - banding: the face gradient is a 1.5% L delta over a bounded panel (not a full-bleed hero), well\n *     within 8-bit tolerance; no large subtle gradient exists, so grain dithering is not required.\n *   - no `transparent` fades anywhere (no fade-to-nothing gradients in the system).\n */\n\n\n/* ===== motion.css ===== */\n/* skill-lab — motion language (single source). Built by atelier:motion.\n * Budget (canon) = restrained → minimal. This is an INSTRUMENT: motion may only orient, show\n * causality, or mask latency — never read as marketing flourish. Compositor-only (transform/opacity).\n * Nothing fires repeatedly or unpredictably during reading.\n */\n\n:root {\n  /* durations — discrete UI ≤200ms; the bar fill (latency-mask/progress) may reach 240ms */\n  --dur-instant: 0ms;     /* focus rings — no transition */\n  --dur-fast:    120ms;   /* hover / press feedback */\n  --dur-base:    180ms;   /* entrance / discrete transitions */\n  --dur-fill:    240ms;   /* result bar grow (progress) */\n  /* easing tokens — entrance ease-out, exit ease-in, A→B ease-in-out */\n  --ease-out:    cubic-bezier(0, 0, 0.2, 1);\n  --ease-in:     cubic-bezier(0.4, 0, 1, 1);\n  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);\n}\n\n/* ---- PURPOSE-CLASSIFIED animations (each maps to a job; nothing decorative) ---- */\n\n/* feedback — primary CTA acknowledges the pointer (transform only) */\n.btn-run { transition: transform var(--dur-fast) var(--ease-out), background-color var(--dur-fast) var(--ease-out); }\n.btn-run:hover:not(:disabled) { transform: translateY(-1px); }\n.btn-run:active:not(:disabled) { transform: translateY(0); }\n\n/* feedback — input/control focus & fill (opacity/colour only; focus ring itself is instant) */\n.field input, .field select { transition: border-color var(--dur-fast) var(--ease-out), opacity var(--dur-fast) var(--ease-out); }\n\n/* progress / latency-mask — result bar grows via scaleX (NEVER width). transform-origin set in layout.css. */\n.bar-fill {\n  transform: scaleX(var(--fill, 0));            /* JS sets --fill = mean/10 (0..1) */\n  transition: transform var(--dur-fill) var(--ease-out);\n}\n\n/* orient — the result panel and freshly-arrived sections fade+rise once on mount (not on every update) */\n@keyframes rise { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }\n.result-panel, .error-block { animation: rise var(--dur-base) var(--ease-out) both; }\n\n/* causality — details disclosure (the review grows from its summary) */\ndetails.trial > .review-body { transform-origin: top; }\n\n/* NOTE on the run log: lines are appended INSTANTLY (first feedback <100ms, latency-mask). They are\n * deliberately NOT animated per-line — animating a fast stream during a run would be noise, and the\n * reading-period rule forbids repeated/unpredictable motion. The streaming itself is the signal. */\n\n/* ---- GESTURE / intent arbitration (STAGE 1) ----\n * This surface has NO drag/swipe/carousel/pinch gestures — only native scroll: the page, plus two\n * inner scrollers (.log, .review-body). The only arbitration needed is scroll-chaining containment,\n * solved declaratively (no non-passive preventDefault, no touch-action hacks). */\n.log, .review-body { overscroll-behavior: contain; }   /* inner scroll won't chain to the page */\n/* All actions have a non-gesture path (buttons/inputs/keyboard); no gesture-only interaction exists. */\n\n/* ---- REDUCED MOTION (STAGE 2): re-tuned, not stripped — snap, keep the meaning ---- */\n@media (prefers-reduced-motion: reduce) {\n  .btn-run, .field input, .field select { transition: none; }\n  .btn-run:hover:not(:disabled) { transform: none; }      /* keep the colour change as feedback */\n  .bar-fill { transition: none; }                          /* bar jumps to position (still shows the value) */\n  .result-panel, .error-block { animation: none; }         /* appears instantly, no translate (vestibular-safe) */\n  /* .skeleton / badge pulse already disabled in layout.css under this query */\n}\n\n/* ---- COMPOSITOR / 60fps (STAGE 2) ----\n * Only transform & opacity are animated anywhere above — no width/height/top/left/margin → no reflow,\n * stays on the compositor thread. No `will-change` left on permanently. The bar track clips the\n * rounded fill via overflow:hidden (layout.css). Colour transitions are on tokens already in oklch. */\n";

// ============================ embedded engine (verbatim from core.mjs) ============================
// core.mjs — the experiment engine. Pure ESM; runs in Node and the browser.
//
// It does NOT know how to reach a model: you inject callReview/callGrade (built by
// providers.mjs). That is what lets the identical experiment run on claude.ai
// (proxy auth) or locally against your own provider (dsv4 / DeepSeek / …).
//
// The design, in one breath:
//   target  = the OLD code, before a real maintainer touched it
//   answer  = the maintainer's ACTUAL diff  (ground truth we did not author)
//   metric  = did the review recommend the same change the maintainer made?
//   control = run the same review on the AFTER code; if it still flags the
//             already-removed problem, that is a measurable false positive.

// The review framing is PER-SKILL (see evals/<skill>/profile.json): a short `domain`
// label ("state architecture", …) and the reviewer's system prompt. The engine below
// is domain-agnostic — swapping the profile is what re-points it at another skill.
const DEFAULT_REVIEW_SYSTEM =
  "You are a senior engineer reviewing code. Identify the real problems and give concrete, specific fixes. Be concise.";

// The ONLY manipulated variable: whether the skill's text is prepended.
function reviewMessages({ code, skillText, domain = "architecture" }) {
  const D = domain.toUpperCase();
  const task = skillText
    ? "Follow this skill methodology when reviewing:\n\n" + skillText +
      "\n\n---\nNow review the " + D + " of this component:\n\n" + code
    : "Review the " + D + " of this component. List the problems and concrete fixes:\n\n" + code;
  return [{ role: "user", content: task }];
}

// The grader NEVER sees the skill, nor which condition produced the review. The
// maintainer's REAL diff is a KNOWN-GOOD REFERENCE, not the only right answer: the
// review is scored on whether its recommendations are genuine, correct improvements
// to THIS code — reproducing the maintainer's change OR proposing a different one
// that is equally good or better. Independence is preserved (the judge is a separate
// model, not the skill's author); the bar is concreteness + correctness.
function gradeReviewMessages({ code, diff, review, domain = "architecture" }) {
  return [{
    role: "user",
    content:
      "You are STRICTLY judging the quality of a code review focused on " + domain + ".\n\n" +
      "The code that was reviewed (BEFORE any change):\n--- CODE ---\n" + code + "\n--- END CODE ---\n\n" +
      "For CALIBRATION ONLY, here is ONE real improvement a maintainer later made to this code — a REFERENCE " +
      "example proving the code genuinely has real " + domain + " problems at this level. It is NOT the only valid " +
      "finding, NOT a checklist, NOT an answer key. The review is NOT required to match it. A review that finds " +
      "DIFFERENT but equally-real, equally-important problems is JUST AS GOOD. Do NOT reward a review for matching " +
      "this, nor penalize it for missing this specific one:\n" +
      "--- ONE REFERENCE IMPROVEMENT (calibration, NOT the answer key) ---\n" + diff + "\n--- END ---\n\n" +
      "The review under judgement:\n--- REVIEW ---\n" + review + "\n--- END REVIEW ---\n\n" +
      "Grade the review on its OVERALL MERIT as a " + domain + " review of THIS code: how many genuinely real, " +
      "important problems does it identify, and how correct and concrete are its fixes? Pick the band by the " +
      "OBSERVABLE criteria below, not by impression, and NOT by whether it matched the reference.\n\n" +
      "STEP 1 — diagnose (state these in `why`):\n" +
      "  • found   — identifies at least one GENUINELY REAL, important problem in this code (the reference issue OR a different equally-real one)?  yes / partial / no\n" +
      "  • fixes   — correct & concrete (names what to change, would actually work)?  correct / mixed / incorrect / vague\n" +
      "  • harmful — does ANY recommendation give actively WRONG advice — introduce a bug, break working behavior, or push a clearly WORSE design?  yes / no\n" +
      "  • depth   — how much real, correct value: a single solid finding, several genuine ones, or deep/important ones?  thin / solid / rich\n" +
      "  • noise   — mostly cosmetic / stylistic / generic filler?  clean / some / mostly\n\n" +
      "STEP 2 — pick the band by QUALITY (for calibration, the one reference improvement ON ITS OWN is a 'solid' single finding ≈ 6-7; a review can equal it with a DIFFERENT real finding, fall short, or beat it with more/deeper real ones):\n" +
      "  10 = RARE & flawless: the most important real problem(s) with excellent, concrete, correct fixes; >=2 genuine issues; ZERO incorrect or vague points; no filler — a senior applies it wholesale. Any nameable flaw → not a 10.\n" +
      "   9 = excellent: real, important problems with correct concrete fixes; ONE small blemish (one vague fix / minor miss / a little filler)\n" +
      "   8 = strong & thorough: several genuine, correct, concrete " + domain + " problems; minor noise OK; no harm\n" +
      "   7 = good: at least one solid real problem well-fixed + some extra real value, with notable vagueness or one minor incorrect side-point\n" +
      "   6 = solid: one genuinely real, important problem identified with a correct, concrete fix; no harm; little extra\n" +
      "   5 = partial: a real problem with a vague/partial fix, or only one minor genuine issue\n" +
      "   4 = weak: real issues present BUT the main recommendation is wrong/impractical/wouldn't help, or a genuine point offset by an incorrect (non-harmful) one\n" +
      "   3 = one small real point buried in vague/cosmetic/incorrect suggestions\n" +
      "   2 = cosmetic/stylistic/trivial only (naming, micro-perf), no real " + domain + " improvement\n" +
      "   1 = generic boilerplate, nothing specific to this code\n" +
      "   0 = empty / no recommendations\n\n" +
      "STEP 3 — apply HARD OVERRIDES (they win over the band):\n" +
      "  • HARM: if `harmful` is yes, the score MAY NOT EXCEED 4; if the harmful rec is the review's MAIN thrust, score 0-2.\n" +
      "  • NO REAL FINDING: if `found` = no (identifies no genuinely real problem at all), the score MAY NOT EXCEED 4.\n" +
      "  • EMPTY: no concrete recommendation at all → 0.\n" +
      "  • LENGTH IS NOT VALUE: never reward length or point-count; only correct, concrete " + domain + " improvements count. Cosmetic/style/micro-perf earn nothing. A long sprawling review is not better than a tight one with the same real points.\n" +
      "  • CONCRETENESS: a recommendation that does not say WHAT to change is `vague` and does not count.\n" +
      "  • MATCHING THE REFERENCE EARNS NO BONUS and MISSING IT IS NO PENALTY: judge real-problem-finding wherever it lands.\n\n" +
      'Return ONLY JSON: {"found": "yes"|"partial"|"no", "harmful": true|false, "score": <integer 0-10>, "why": "one sentence naming the band and any override"}.',
  }];
}

// False-positive probe. The AFTER code already has THIS issue fixed. Did the review
// re-raise the very thing the maintainer resolved, or tell us to undo it? Generic
// across skills: the after-code may still contain OTHER, unrelated issues, and a
// review is free to mention those — only re-raising the RESOLVED issue counts.
function falsePositiveMessages({ diff, review, domain = "architecture" }) {
  return [{
    role: "user",
    content:
      "A maintainer already FIXED a code issue with the change below:\n\n" +
      "--- THE FIX (already applied) ---\n" + diff + "\n--- END ---\n\n" +
      "Below is a " + domain + " review of the ALREADY-FIXED code. Count it as a FALSE POSITIVE " +
      "ONLY IF the review re-raises the very problem this fix already resolved, or tells us to undo / revert " +
      "the change. Comments about OTHER, still-present issues DO NOT count.\n\n" +
      "--- REVIEW ---\n" + review + "\n--- END REVIEW ---\n\n" +
      'Return ONLY JSON: {"false_positive": true | false, "why": "one sentence"}.',
  }];
}

function parseJSON(text) {
  const clean = String(text).replace(/```json|```/g, "").trim();
  const s = clean.indexOf("{"), e = clean.lastIndexOf("}");
  if (s === -1 || e === -1) throw new Error("grader did not return JSON: " + clean.slice(0, 120));
  return JSON.parse(clean.slice(s, e + 1));
}
const clampScore = (s) => { const n = Math.round(Number(s)); return Number.isFinite(n) ? Math.max(0, Math.min(10, n)) : 0; };

// Turn a grader reply into the final score, ENFORCING the overrides in code (not just in
// the prompt). Shared by every grade consumer so the rubric's floor is mechanical.
// NOTE: the maintainer's diff is now ONLY a calibration reference, never the anchor — so
// there is NO "missed the reference → cap" rule. `found` means "found ANY genuinely-real
// problem" (reference or a different equally-real one); finding no real problem at all,
// or giving actively-harmful advice, is what caps the score.
function scoreFromGrade(g) {
  let s = clampScore(g?.score);
  if (g?.harmful === true) s = Math.min(s, 4);   // actively wrong/harmful advice → never "good"
  if (g?.found === "no") s = Math.min(s, 4);      // identifies no genuinely-real problem → weak (NOT "missed the specific reference")
  return s;
}

// CONSENSUS grading — the grader is noisy (same review, temp 0, still wobbles ±2-3),
// so one grade is unreliable. Grade TWICE and average; if the two disagree by more
// than `threshold`, grade a THIRD time and take the MEDIAN of the three (robust to
// the outlier). Each grade gets the harm/ceiling caps before comparison.
async function gradeConsensus({ callGrade, code, diff, review, domain = "architecture", threshold = 2, maxTokens = 8000 }) {
  const one = async () => {
    const g = await callForJSON(callGrade, gradeReviewMessages({ code, diff, review, domain }), { maxTokens, temperature: 0 });
    return { score: scoreFromGrade(g), harmful: g.harmful === true, found: g.found, why: g.why };
  };
  const grades = [await one(), await one()];
  const escalated = Math.abs(grades[0].score - grades[1].score) > threshold;
  if (escalated) grades.push(await one());
  const sorted = grades.map((g) => g.score).sort((a, b) => a - b);
  const score = escalated ? sorted[1] : (sorted[0] + sorted[1]) / 2; // median of 3, else mean of 2
  return { score, scores: grades.map((g) => g.score), escalated, grades };
}

// FALSE-POSITIVE grade — grade a review of the ALREADY-FIXED code: does it re-raise the
// resolved problem (cry wolf)? Single grade (it's a boolean, not a noisy 0–10 score, so no
// consensus). Shared by both arms so their cry-wolf rates are measured the same way.
async function gradeFalsePositive({ callGrade, diff, review, domain = "architecture", maxTokens = 8000 }) {
  const fp = await callForJSON(callGrade, falsePositiveMessages({ diff, review, domain }), { maxTokens, temperature: 0 });
  return { falsePositive: fp.false_positive === true, why: fp.why };
}

// A REAL but SMALL agentic loop — draft, then self-revise — run IDENTICALLY on both arms.
// The ONLY difference between arms is whether `skillText` (the skill's guidance) sits in context,
// so the SKILL's CONTENT is the single manipulated variable and the process is held fixed. (Not
// the heavy gated harness; deliberately small so "with vs without skill" is a clean comparison.)
async function runMiniHarness({ callModel, code, skillText = null, domain = "architecture", system, maxTokens = 8000, onEvent = () => {} }) {
  const sys = system || DEFAULT_REVIEW_SYSTEM;
  const base = reviewMessages({ code, skillText, domain });
  onEvent({ phase: "draft" });
  const draft = await callModel(base, { system: sys, maxTokens, temperature: 1 });
  onEvent({ phase: "revise" });
  const messages = [...base, { role: "assistant", content: draft },
    { role: "user", content: "Critique your own review: which REAL problems did you miss, and where are you flagging issues that aren't actually there? Then write your FINAL review — the real problems and concrete, specific fixes — as plain prose. Be concise." }];
  const final = (await callModel(messages, { system: sys, maxTokens, temperature: 1 }) || "").trim();
  return { review: final || draft, turns: 2, draft };
}

// Real models occasionally wrap the JSON in prose, omit it, or get truncated before
// emitting it. Ask, parse, and on failure retry ONCE with a firmer nudge — so one
// stray grader reply doesn't abort the whole run.
async function callForJSON(call, messages, opts) {
  let lastErr;
  for (let attempt = 0; attempt < 2; attempt++) {
    const msgs = attempt === 0
      ? messages
      : messages.map((m, i) =>
          i === messages.length - 1
            ? { ...m, content: m.content + "\n\nIMPORTANT: reply with ONLY the JSON object, nothing before or after it." }
            : m);
    const text = await call(msgs, opts);
    try { return parseJSON(text); } catch (e) { lastErr = e; }
  }
  throw lastErr;
}

// One trial = one record: review the OLD code → grade against the maintainer's real
// diff, and (optionally) review the FIXED code → false-positive check. This is the
// independent unit of work; the web bench fans many of these out with mapPool().
// onEvent({ phase, trial }) drives a live log; optional (the terminal ignores it).
async function runTrial({ callReview, callGrade, fixture, skillText, withFP, trial = 1, profile = {}, consensus = false, threshold = 2, onEvent = () => {} }) {
  const domain = profile.domain || "architecture";
  const system = profile.reviewSystem || DEFAULT_REVIEW_SYSTEM;

  onEvent({ phase: "review", trial });
  const review = await callReview(reviewMessages({ code: fixture.before, skillText, domain }), {
    system, maxTokens: 16000, temperature: 1,
  });
  onEvent({ phase: "grade", trial });
  let rec;
  if (consensus) {
    // multi-grade: grade 2×, escalate to a 3rd + median on disagreement (robust to the noisy grader)
    const c = await gradeConsensus({ callGrade, code: fixture.before, diff: fixture.diff, review, domain, threshold });
    const harmMajority = c.grades.filter((x) => x.harmful).length > c.grades.length / 2;
    rec = { trial, foundScore: c.score, foundWhy: c.grades[0].why, found: c.grades[0].found, harmful: harmMajority, review,
      gradeScores: c.scores, gradeEscalated: c.escalated };
  } else {
    const g = await callForJSON(callGrade, gradeReviewMessages({ code: fixture.before, diff: fixture.diff, review, domain }), {
      maxTokens: 8000, temperature: 0,
    });
    rec = { trial, foundScore: scoreFromGrade(g), foundWhy: g.why, found: g.found, harmful: g.harmful === true, review };
  }

  if (withFP) {
    // Same review task on the ALREADY-FIXED code → does it cry wolf?
    onEvent({ phase: "fp-review", trial });
    const cleanReview = await callReview(reviewMessages({ code: fixture.after, skillText, domain }), {
      system, maxTokens: 16000, temperature: 1,
    });
    onEvent({ phase: "fp-grade", trial });
    const fp = await callForJSON(callGrade, falsePositiveMessages({ diff: fixture.diff, review: cleanReview, domain }), {
      maxTokens: 8000, temperature: 0,
    });
    rec.falsePositive = fp.false_positive === true;
    rec.fpWhy = fp.why;
    rec.cleanReview = cleanReview;
  }
  onEvent({ phase: "trial-done", trial, foundScore: rec.foundScore, falsePositive: rec.falsePositive });
  return rec;
}

// Run one fixture under one condition for N trials, sequentially. Used by the
// terminal runner; the web bench fans trials out concurrently via mapPool instead.
async function runCell({ callReview, callGrade, fixture, skillText, trials, withFP, profile, onEvent = () => {} }) {
  const out = [];
  for (let t = 1; t <= trials; t++) {
    out.push(await runTrial({ callReview, callGrade, fixture, skillText, withFP, trial: t, profile, onEvent }));
  }
  return out;
}

// Bounded-concurrency map: at most `limit` invocations of fn in flight at once.
// Lets the web bench overlap model calls without flooding the provider (429s).
async function mapPool(items, limit, fn) {
  const out = new Array(items.length);
  let next = 0;
  const worker = async () => {
    while (next < items.length) {
      const idx = next++;
      out[idx] = await fn(items[idx], idx);
    }
  };
  await Promise.all(Array.from({ length: Math.max(1, Math.min(limit, items.length)) }, worker));
  return out;
}

function summarize(records) {
  const n = records.length || 1;
  const meanFound = records.reduce((a, r) => a + r.foundScore, 0) / n;
  const fpRows = records.filter((r) => "falsePositive" in r);
  const fpRate = fpRows.length ? fpRows.filter((r) => r.falsePositive).length / fpRows.length : null;
  return { meanFound, fpRate, n: records.length };
}

const core = { DEFAULT_REVIEW_SYSTEM, reviewMessages, gradeReviewMessages, falsePositiveMessages, scoreFromGrade, gradeConsensus, gradeFalsePositive, runMiniHarness, runTrial, runCell, mapPool, summarize };

